1566   BasicBlock *BB = I->getParent();
1567   for (Value *Op : I->operands()) {
1568     if (auto *J = dyn_cast<Instruction>(Op))
1569       if (J->getParent() == BB)
1570         return false;
1571   }
1572 
1573   return true;
